## 2. Type-Safe Builder Pattern with Ordered Methods

This implementation uses phantom types to track builder state and enforce method order.

```typescript
// ============================================================
// BUILDER PATTERN WITH COMPILE-TIME ORDER ENFORCEMENT
// ============================================================

/**
 * Phantom types to track which properties have been set
 * These exist only at compile time
 */
type NotSet = { readonly _brand: 'NotSet' };
type Set = { readonly _brand: 'Set' };

/**
 * The data being built
 */
interface PersonData {
  name: string;
  age: number;
  email?: string;
}

/**
 * Builder state tracking interface
 * Generic parameters track which fields have been set
 */
interface BuilderState<
  NameState extends NotSet | Set,
  AgeState extends NotSet | Set,
> {
  _nameState: NameState;
  _ageState: AgeState;
}

/**
 * The Builder class with state-dependent methods
 */
class PersonBuilder<
  NameState extends NotSet | Set = NotSet,
  AgeState extends NotSet | Set = NotSet,
> {
  private data: Partial<PersonData> = {};

  // Private constructor - use static create() method
  private constructor(data: Partial<PersonData> = {}) {
    this.data = { ...data };
  }

  /**
   * Create a new builder - this is the only entry point
   */
  static create(): PersonBuilder<NotSet, NotSet> {
    return new PersonBuilder();
  }

  /**
   * setName is ONLY available when name has NOT been set
   * Returns a builder with NameState = Set
   */
  setName(
    this: PersonBuilder<NotSet, AgeState>,
    name: string
  ): PersonBuilder<Set, AgeState> {
    const newBuilder = new PersonBuilder<Set, AgeState>({
      ...this.data,
      name,
    });
    return newBuilder;
  }

  /**
   * setAge is ONLY available when:
   * - Name HAS been set (NameState = Set)
   * - Age has NOT been set (AgeState = NotSet)
   */
  setAge(
    this: PersonBuilder<Set, NotSet>,
    age: number
  ): PersonBuilder<Set, Set> {
    const newBuilder = new PersonBuilder<Set, Set>({
      ...this.data,
      age,
    });
    return newBuilder;
  }

  /**
   * Optional method - can be called anytime after required fields
   */
  setEmail(
    this: PersonBuilder<Set, Set>,
    email: string
  ): PersonBuilder<Set, Set> {
    const newBuilder = new PersonBuilder<Set, Set>({
      ...this.data,
      email,
    });
    return newBuilder;
  }

  /**
   * build() is ONLY available when ALL required fields are set
   */
  build(this: PersonBuilder<Set, Set>): PersonData {
    return this.data as PersonData;
  }
}

