## 2. Builder Pattern with Ordered Method Calls

```typescript
// State tracking types
type BuilderState = {
  name: boolean;
  age: boolean;
};

// The built result
type Person = {
  name: string;
  age: number;
};

// Builder class with state tracking
class PersonBuilder<State extends BuilderState = { name: false; age: false }> {
  private data: Partial<Person> = {};

  // setName can only be called when name is false (not yet set)
  setName<S extends State>(
    this: S extends { name: false } ? PersonBuilder<S> : never,
    name: string
  ): PersonBuilder<{ name: true; age: State['age'] }> {
    this.data.name = name;
    return this as any;
  }

  // setAge can only be called when age is false AND name is true
  setAge<S extends State>(
    this: S extends { name: true; age: false } ? PersonBuilder<S> : never,
    age: number
  ): PersonBuilder<{ name: true; age: true }> {
    this.data.age = age;
    return this as any;
  }

  // build can only be called when both name and age are true
  build<S extends State>(
    this: S extends { name: true; age: true } ? PersonBuilder<S> : never
  ): Person {
    return this.data as Person;
  }
}

function createPersonBuilder(): PersonBuilder<{ name: false; age: false }> {
  return new PersonBuilder();
}

// ✓ Valid - correct order
const person1 = createPersonBuilder()
  .setName('Alice')
  .setAge(25)
  .build();

console.log(person1); // { name: 'Alice', age: 25 }

// ✗ Compile errors

// @ts-expect-error - Cannot call setAge before setName
const person2 = createPersonBuilder()
  .setAge(25)
  .setName('Bob')
  .build();

// @ts-expect-error - Cannot build without setting age
const person3 = createPersonBuilder()
  .setName('Charlie')
  .build();

// @ts-expect-error - Cannot build without setting anything
const person4 = createPersonBuilder()
  .build();

// @ts-expect-error - Cannot call setName twice
const person5 = createPersonBuilder()
  .setName('David')
  .setName('Eve')
  .setAge(30)
  .build();

// @ts-expect-error - Cannot call setAge twice
const person6 = createPersonBuilder()
  .setName('Frank')
  .setAge(30)
  .setAge(31)
  .build();
