## 2. Builder Pattern with Method Order Enforcement

```typescript
// Builder state machine types
type EmptyBuilder = { _state: 'empty' };
type WithName = { _state: 'nameSet'; name: string };
type WithAge = { _state: 'ageSet'; age: number };
type WithBoth = { _state: 'bothSet'; name: string; age: number };

class Builder<T extends { _state: string }> {
  private state: T;

  constructor(state: T) {
    this.state = state;
  }

  // setName can only be called on empty builder
  setName<K extends T extends EmptyBuilder ? string : never>(
    name: K
  ): Builder<WithName> {
    return new Builder<WithName>({ _state: 'nameSet', name });
  }

  // setAge can only be called after setName
  setAge<K extends T extends WithName ? number : never>(
    age: K
  ): Builder<WithBoth> {
    const withName = this.state as WithName;
    return new Builder<WithBoth>({
      _state: 'bothSet',
      name: withName.name,
      age
    });
  }

  // build can only be called after both name and age are set
  build(): T extends WithBoth ? Person : never {
    const withBoth = this.state as WithBoth;
    return { name: withBoth.name, age: withBoth.age } as any;
  }
}

interface Person {
  name: string;
  age: number;
}

// Helper function to start the builder
function builder(): Builder<EmptyBuilder> {
  return new Builder<EmptyBuilder>({ _state: 'empty' });
}

// Example usage
const person1 = builder()
  .setName('Alice')
  .setAge(30)
  .build(); // ✓ Compiles

// These will cause compile errors:
// const person2 = builder().setAge(25).setName('Bob').build(); // ✗ Wrong order
// const person3 = builder().setName('Bob').build(); // ✗ Age not set
// const person4 = builder().build(); // ✗ Nothing set

// You can also create a more fluent version with method chaining:
type BuilderState = EmptyBuilder | WithName | WithBoth;

class FluentBuilder<T extends BuilderState> {
  private state: T;

  constructor(state: T) {
    this.state = state;
  }

  setName(name: string): T extends EmptyBuilder 
    ? FluentBuilder<WithName> 
    : never {
    if (this.state._state === 'empty') {
      return new FluentBuilder<WithName>({ _state: 'nameSet', name }) as any;
    }
    throw new Error('Invalid state');
  }

  setAge(age: number): T extends WithName 
    ? FluentBuilder<WithBoth> 
    : never {
    if (this.state._state === 'nameSet') {
      const withName = this.state as WithName;
      return new FluentBuilder<WithBoth>({
        _state: 'bothSet',
        name: withName.name,
        age
      }) as any;
    }
    throw new Error('Invalid state');
  }

  build(): T extends WithBoth ? Person : never {
    if (this.state._state === 'bothSet') {
      return this.state as any;
    }
    throw new Error('Invalid state');
  }
}

// Usage of fluent builder
const fluentBuilder = new FluentBuilder<EmptyBuilder>({ _state: 'empty' });
const person5 = fluentBuilder.setName('Charlie').setAge(35).build(); // ✓
```

